= -2; // The remainder of 7 / 5modulo(-7, 5) === 3; // n %% 5 is always between 0 and 4tabs.selectTabAtIndex(modulo(tabs.currentIndex - count, tabs.length));var volume, winner;if (ignition === true) &#123; launch();&#125;if (band !== SpinalTap) &#123; volume = 10;&#125;if (answer !== false) &#123; letTheWildRumpusBegin();&#125;if (car.speed &lt; limit) &#123; accelerate();&#125;if (pick === 47 || pick === 92 || pick === 13) &#123; winner = true;&#125;print(inspect(`My name is $&#123;this.name&#125;`)); 存在操作符在 JavaScript 中确认一个变量是否存在是很困难的。因为if (variable) 不仅会在变量不存在时生效，在变量为0值（0,空字符串，false）时也会生效。CoffeeScript 的?操作符只在变量为null和 undefined的时候返回false，这很像 Ruby 中的 nil？(实际上高版本的 ES 也会有一个叫 Null Propagation Operator的类似特性)。 这样我们就可以做更加安全的条件赋值了（比a = a || value安全）。 123456solipsism = true if mind? and not world?speed = 0speed ?= 15footprints = yeti ? &quot;bear&quot; 1234567891011var footprints, solipsism, speed;if ((typeof mind !== &quot;undefined&quot; &amp;&amp; mind !== null) &amp;&amp; (typeof world === &quot;undefined&quot; || world === null)) &#123; solipsism = true;&#125;speed = 0;if (speed == null) &#123; speed = 15;&#125; 注意看，一个?被翻译成了对undefined和null的严格求不等!==。但是，?与unless搭配的时候，就会被翻译成==。 1234major = &#x27;Computer Science&#x27;unless major? signUpForClass &#x27;Introduction to Wines&#x27; 1234567var major;major = &#x27;Computer Science&#x27;;if (major == null) &#123; signUpForClass(&#x27;Introduction to Wines&#x27;);&#125; 可以用存在操作符来达到其他语言中经常出现的流利调用，流利调用失败用户会得到undefined而不会出现烦人的空指针（在 JavaScript 中实际上是不能在undefined上调用特定成员的TypeError）异常： 1zip = lottery.drawWinner?().address?.zipcode 123var ref, zip;zip = typeof lottery.drawWinner === &quot;function&quot; ? (ref = lottery.drawWinner().address) != null ? ref.zipcode : void 0 : void 0; 无括号的链式调用用.和断行缩进可以像其他脚本语言一样进行无括号链式调用： 123456$ &#x27;body&#x27;.click (e) -&gt; $ &#x27;.box&#x27; .fadeIn &#x27;fast&#x27; .addClass &#x27;show&#x27;.css &#x27;background&#x27;, &#x27;white&#x27; 123$(&#x27;body&#x27;).click(function(e) &#123; return $(&#x27;.b