quot;Blastoff!&quot;);&#125;;countdown(3); 类CoffeeScript 1 就提供了class和extends关键字，作为原型相关函数的语法糖。ES2015吸收了这两个关键字，CoffeeScript 2 直接把这两个关键字编译成 ES2015的类。 123456789101112131415161718192021class Animal constructor: (@name) -&gt; move: (meters) -&gt; alert @name + &quot; moved #&#123;meters&#125;m.&quot;class Snake extends Animal move: -&gt; alert &quot;Slithering...&quot; super 5class Horse extends Animal move: -&gt; alert &quot;Galloping...&quot; super 45sam = new Snake &quot;Sammy the Python&quot;tom = new Horse &quot;Tommy the Palomino&quot;sam.move()tom.move() 123456789101112131415161718192021222324252627282930313233343536var Animal, Horse, Snake, sam, tom;Animal = class Animal &#123; constructor(name) &#123; this.name = name; &#125; move(meters) &#123; return alert(this.name + ` moved $&#123;meters&#125;m.`); &#125;&#125;;Snake = class Snake extends Animal &#123; move() &#123; alert(&quot;Slithering...&quot;); return super.move(5); &#125;&#125;;Horse = class Horse extends Animal &#123; move() &#123; alert(&quot;Galloping...&quot;); return super.move(45); &#125;&#125;;sam = new Snake(&quot;Sammy the Python&quot;);tom = new Horse(&quot;Tommy the Palomino&quot;);sam.move();tom.move(); 可以用@开头的函数来定义静态方法： 123456789class Teenager @say: (speech) -&gt; words = speech.split &#x27; &#x27; fillers = [&#x27;uh&#x27;, &#x27;um&#x27;, &#x27;like&#x27;, &#x27;actually&#x27;, &#x27;so&#x27;, &#x27;maybe&#x27;] output = [] for word, index in words output.push word output.push fillers[Math.floor(Math.random() * fillers.length)] unless index is words.length - 1 output.join &#x27;, &#x27; 12345678910111213141516171819var Teenager;Teenager = class Teenager &#123; static say(speech) &#123; var fillers, i, index, len, output, word, words; words = speech.split(&#x27; &#x27;); fillers = [&#x27;uh&#x27;, &#x27;um&#x27;, &#x27;like&#x27;, &#x27;actually&#x27;, &#x27;so&#x27;, &#x27;maybe&#x27;]; output = []; for (index = i = 0, len = words.length; i &lt; len; index = ++i) &#123; word = words[index]; output.push(word); if (index !== words.length - 1) &#123; output.push(fillers[Math.floor(Math.random() * fillers.length)]); &#125; &#125; return output.join(&#x27;, &#x27;); &#125;&#125;; 原型式继承ES2015提供了一个短路操作符给原型链相关的操作： 12String::dasherize = -&gt; this.replace /_/g, &quot;-&quot; 123String.prototype.dasherize = function() &#123; return this.replace(/_/g, &quot;-&quot;);&#125;; Switch/When/ElseCoffeeScript 中的switch不用担心忘记写break出现错误的跳转： 12345678910switch day when &quot;Mon&quot; then go work when &quot;Tue&quot; then go relax when &quot;Thu&quot; then go iceFishing when &quot;Fri&quot;, &quot;Sat&quot; if day is bingoDay go bingo go dancing when &quot;Sun&quot; then go church else go work 1234567891011121314151617181920212223switch (day) &#123; case &quot;Mon&quot;: go(work); break; case &quot;Tue&quot;: go(relax); break; case &quot;Thu&quot;: go(iceFishing); break; case &quot;Fri&quot;: case &quot;Sat&quot;: if (day === bingoDay) &#123; go(bingo); go(dancing); &#125; break; case &quot;Sun&quot;: go(church); break; default: go(work);&#125; 在之前读者已经看到了 CoffeeScript 中大量的语句都可以带有返回值，switch也不例外。以下的例子里面，switch 后面连表达式都没有： 12345678score = 76grade = switch when score &lt; 60 then &#x27;F&#x27; when score &lt; 70 then &#x27;D&#x27; when score &lt; 80 then &#x27;C&#x27; when score &lt; 90 then &#x27;B&#x27; else &#x27;A&#x27;# grade == &#x27;C&#x27; 1234567891011121314151617181920var grade, score;score = 76;grade = (function() &#123; switch (false) &#123; case !(score &lt; 60): return &#x27;F&#x27;; case !(score &lt; 70): return &#x27;D&#x27;; case !(score &lt; 80): return &#x27;C&#x27;; case !(score &lt; 90): return &#x27;B&#x27;; default: return &#x27;A&#x27;; &#125;&#125;)();// grade == &#x27;C&#x27; Try/Catch/FinallyCoffeeScript 中的try/catch/finally块可以完全不带大括号： 1234567try allHellBreaksLoose() catsAndDogsLivingTogether()catch error print errorfinally cleanUp() 1234567891011var error;try &#123; allHellBreaksLoose(); catsAndDogsLivingTogether();&#125; catch (error1) &#123; error = error1; print(error);&#125; finally &#123; cleanUp();&#125; 链式比较CoffeeScript 从 Python 中借来了链式比较，这样范围比较的语句就变得更加简单了。 123cholesterol = 127healthy = 200 &gt; cholesterol &gt; 60 12345var cholesterol, healthy;cholesterol = 127;healthy = (200 &gt; cholesterol &amp;&amp; cholesterol &gt; 60); 块状的正则表达式我们已经看到了块状（多行）字符串和注释，CoffeeScript 同样支持块状正则表达式。模仿自 Perl 的/x修饰符，CoffeeScript 使用///来对多行表达式定界，这样多行的正则比单行的正则就更加可读了： 123456NUMBER = /// ^ 0b[01]+ | # binary ^ 0o[0-7]+ | # octal ^ 0x[\da-f]+ | # hex ^ \d*\.?\d+ (?:e[+-]?\d+)? # decimal///i 123456var NUMBER;NUMBER = /^0b[01]+|^0o[0-7]+|^0x[\da-f]+|^\d*\.?\d+(?:e[+-]?\d+)?/i; // binary// octal// hex// decimal 标签化的模板字面量CoffeeScript 支持 ES2015中的标签化模板字面量，提供了自定义的字符串内插的能力。 12345678upperCaseExpr = (textParts, expressions...) -&gt; textParts.reduce (text, textPart, i) -&gt; text + expressions[i - 1].toUpperCase() + textPartgreet = (name, adjective) -&gt; upperCaseExpr&quot;&quot;&quot; Hi #&#123;name&#125;. You look #&#123;adjective&#125;! &quot;&quot;&quot; 1234567891011var greet, upperCaseExpr;upperCaseExpr = function(textParts, ...expressions) &#123; return textParts.reduce(function(text, textPart, i) &#123; return text + expressions[i - 1].toUpperCase() + textPart; &#125;);&#125;;greet = function(name, adjective) &#123; return upperCaseExpr`Hi $&#123;name&#125;. You look $&#123;adjective&#125;!`;&#125;; 模块CoffeeScript 中的模块和 ES2015中的模块很相似，都是import和export语法： 12345678910111213141516171819202122import &#x27;local-file.coffee&#x27;import &#x27;coffeescript&#x27;import _ from &#x27;underscore&#x27;import * as underscore from &#x27;underscore&#x27;import &#123; now &#125; from &#x27;underscore&#x27;import &#123; now as currentTimestamp &#125; from &#x27;underscore&#x27;import &#123; first, last &#125; from &#x27;underscore&#x27;import utilityBelt, &#123; each &#125; from &#x27;underscore&#x27;export default Mathexport square = (x) -&gt; x * xexport class Mathematics least: (x, y) -&gt; if x &lt; y then x else yexport &#123; sqrt &#125;export &#123; sqrt as squareRoot &#125;export &#123; Mathematics as default, sqrt as squareRoot &#125;export * from &#x27;underscore&#x27;export &#123; max, min &#125; from &#x27;underscore&#x27; 12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849505152535455565758596061import &#x27;local-file.coffee&#x27;;import &#x27;coffeescript&#x27;;import _ from &#x27;underscore&#x27;;import * as underscore from &#x27;underscore&#x27;;import &#123; now&#125; from &#x27;underscore&#x27;;import &#123; now as currentTimestamp&#125; from &#x27;underscore&#x27;;import &#123; first, last&#125; from &#x27;underscore&#x27;;import utilityBelt, &#123; each&#125; from &#x27;underscore&#x27;;export default Math;export var square = function(x) &#123; return x * x;&#125;;export var Mathematics = class Mathematics &#123; least(x, y) &#123; if (x &lt; y) &#123; return x; &#125; else &#123; return y; &#125; &#125;&#125;;export &#123; sqrt&#125;;export &#123; sqrt as squareRoot&#125;;export &#123; Mathematics as default, sqrt as squareRoot&#125;;export * from &#x27;underscore&#x27;;export &#123; max, min&#125; from &#x27;underscore&#x27;; 嵌入式 JavaScript在 CoffeeScript 中可以用倒引号（`）直接引用 JavaScript 代码： 12345678hi = `function() &#123; return [document.title, &quot;Hello JavaScript&quot;].join(&quot;: &quot;);&#125;`# \`会被编译成`，\\`会被编译成\`markdown = `function () &#123; return \`In Markdown, write code like \\`this\\`\`;&#125;` 1234567891011var hi;hi = function() &#123; return [document.title, &quot;Hello JavaScript&quot;].join(&quot;: &quot;);&#125;;var markdown;markdown = function () &#123; return `In Markdown, write code like \`this\``;&#125;; 用三个倒引号可以很轻松地引用一大块 JavaScript 代码： 12345\```function time() &#123; return `The time is $&#123;new Date().toLocaleTimeString()&#125;`;&#125;\``` 1234function time() &#123; return `The time is $&#123;new Date().toLocaleTimeString()&#125;`;&#125;; JSXCoffeeScript 不需要专门的插件或者设置，就可以理解 JSX。 同普通的 JSX 一样，&lt;和&gt;指明了XML 元素，由 &#123;和&#125;包围的代码会被内插替换。为了避免和大于、小于的比较混淆，类似i &lt; len的代码必须带空格，不能写作i&lt;len。编译器有时候能够在你忘记加空格的时候，猜到你的意图，但不要心怀侥幸，还是要尽量自己加空格。 123456789renderStarRating = (&#123; rating, maxStars &#125;) -&gt; &lt;aside title=&#123;&quot;Rating: #&#123;rating&#125; of #&#123;maxStars&#125; stars&quot;&#125;&gt; &#123;for wholeStar in [0...Math.floor(rating)] &lt;Star className=&quot;wholeStar&quot; key=&#123;wholeStar&#125; /&gt;&#125; &#123;if rating % 1 isnt 0 &lt;Star className=&quot;halfStar&quot; /&gt;&#125; &#123;for emptyStar in [Math.ceil(rating)...maxStars] &lt;Star className=&quot;emptyStar&quot; key=&#123;emptyStar&#125; /&gt;&#125; &lt;/aside&gt; 123456789101112131415161718192021222324var renderStarRating;renderStarRating = function(&#123;rating, maxStars&#125;) &#123; var emptyStar, wholeStar; return &lt;aside title=&#123;`Rating: $&#123;rating&#125; of $&#123;maxStars&#125; stars`&#125;&gt; &#123;(function() &#123; var i, ref, results; results = []; for (wholeStar = i = 0, ref = Math.floor(rating); 0 &lt;= ref ? i &lt; ref : i &gt; ref; wholeStar = 0 &lt;= ref ? ++i : --i) &#123; results.push(&lt;Star className=&quot;wholeStar&quot; key=&#123;wholeStar&#125; /&gt;); &#125; return results; &#125;)()&#125; &#123;(rating % 1 !== 0 ? &lt;Star className=&quot;halfStar&quot; /&gt; : void 0)&#125; &#123;(function() &#123; var i, ref, ref1, results; results = []; for (emptyStar = i = ref = Math.ceil(rating), ref1 = maxStars; ref &lt;= ref1 ? i &lt; ref1 : i &gt; ref1; emptyStar = ref &lt;= ref1 ? ++i : --i) &#123; results.push(&lt;Star className=&quot;emptyStar&quot; key=&#123;emptyStar&#125; /&gt;); &#125; return results; &#125;)()&#125; &lt;/aside&gt;;&#125;; 类型注解Flow 风格的注释式类型注解可以在 CoffeeScript 中提供静态类型检查的能力（TypeScript 的粉丝可能要头痛了）： 1234567891011# @flow###::type Obj = &#123; num: number,&#125;;###fn = (str ###: string ###, obj ###: Obj ###) ###: string ### -&gt; str + obj.num 1234567891011// @flow/*::type Obj = &#123; num: number,&#125;;*/var fn;fn = function(str/*: string */, obj/*: Obj */)/*: string */ &#123; return str + obj.num;&#125;; 如果用户已经成功安装了 Flow 和最新的 CoffeeScript，可以用如下命令进行类型检查： 1coffee --bare --no-header --compile app.coffee &amp;&amp; npm run flow --bare --no-header非常重要，因为 Flow 要求文件中的第一行是// @flow注释。
